import { genkit, z } from "genkit";
import { googleAI, gemini15Flash } from "@genkit-ai/googleai";
import { AnalysisResult } from "@/types/analysis";

const ai = genkit({
    plugins: [googleAI()],
    model: gemini15Flash,
});

// Define the schema for the analysis result
const AnalysisSchema = z.object({
    summary: z.string().describe("A high-level summary of the codebase's purpose and functionality."),
    techStack: z.object({
        languages: z.array(z.string()).describe("List of programming languages detected."),
        frameworks: z.array(z.string()).describe("List of frameworks and libraries detected."),
        tools: z.array(z.string()).describe("List of build tools, linters, etc."),
        packageManager: z.string().describe("The package manager used (e.g., npm, yarn, pnpm)."),
    }),
    complexity: z.object({
        score: z.number().min(1).max(10).describe("Complexity score from 1-10."),
        analysis: z.string().describe("Explanation of the complexity score."),
        metrics: z.object({
            totalFiles: z.number(),
            totalLines: z.number(),
            avgLinesPerFile: z.number(),
        }),
    }),
    architecture: z.string().describe("A Mermaid.js graph TD diagram string representing the high-level architecture. Do NOT include markdown code blocks (```mermaid), just the diagram code."),
    errors: z.array(z.object({
        file: z.string(),
        line: z.number(),
        type: z.string(),
        message: z.string(),
        severity: z.string(),
    })).describe("List of potential errors or bugs found."),
    warnings: z.array(z.object({
        file: z.string(),
        line: z.number(),
        type: z.string(),
        message: z.string(),
        severity: z.string(),
    })).describe("List of code quality warnings."),
    packages: z.object({
        outdated: z.array(z.object({
            name: z.string(),
            current: z.string(),
            latest: z.string(),
            status: z.string(),
        })).describe("List of potentially outdated packages (based on common knowledge, not live npm check)."),
        total: z.number(),
        dependencies: z.record(z.string()),
        devDependencies: z.record(z.string()),
    }),
    fileAnalysis: z.array(z.object({
        path: z.string(),
        language: z.string(),
        lines: z.number(),
        size: z.number(),
        purpose: z.string().describe("The specific purpose of this file."),
        keyFeatures: z.array(z.string()).describe("Key features or functions implemented in this file."),
        preview: z.string().describe("A short snippet of the code (first few lines or relevant part)."),
    })).describe("Detailed analysis of the most important files (limit to top 10-15)."),
    qualityAnalysis: z.array(z.object({
        category: z.string(),
        issue: z.string(),
        recommendation: z.string(),
        priority: z.string(),
    })).describe("Actionable recommendations for code quality, security, etc."),
});

export async function analyzeCodebase(files: { path: string; content: string }[]): Promise<AnalysisResult> {
    // Prepare the context from files
    // Limit context size if necessary, but Gemini 1.5 Flash has a large window.
    // We'll prioritize package.json, README, and source files.

    const fileContext = files.map(f => `File: ${f.path}\nContent:\n${f.content}\n---`).join("\n");

    const prompt = `
    Analyze the following codebase and provide a detailed report.
    
    Focus on:
    1. Understanding the overall purpose and architecture.
    2. Identifying the tech stack.
    3. Assessing code quality and complexity.
    4. Generating a Mermaid.js diagram for the architecture.
    5. Providing a file-by-file breakdown of the most significant files.
    6. Identifying potential errors, warnings, and security issues.
    
    Files provided:
    ${fileContext}
    `;

    try {
        const { output } = await ai.generate({
            prompt: prompt,
            output: { schema: AnalysisSchema },
        });

        if (!output) {
            throw new Error("Failed to generate analysis");
        }

        return output;
    } catch (error) {
        console.error("Genkit analysis error:", error);
        throw error;
    }
}

export async function chatWithCodebase(
    history: { role: "user" | "model"; content: string }[],
    message: string,
    context: string
) {
    const historyText = history.map(h => `${h.role === 'user' ? 'User' : 'Model'}: ${h.content}`).join('\n');

    const chatPrompt = `
    You are CodeSonar, an expert AI code analyst.
    You have analyzed a codebase and here is the context summary:
    ${context}

    History of conversation:
    ${historyText}

    Answer the user's question based on this context.
    Be helpful, specific, and technical.
    If you need to reference specific files or code, do so.
    
    User Question: ${message}
    `;

    try {
        const { text } = await ai.generate({
            prompt: chatPrompt,
        });
        return text;
    } catch (error) {
        console.error("Chat error:", error);
        return "I'm sorry, I encountered an error while processing your request.";
    }
}
